."}]$alchemy_v9$::jsonb)
  AS x(item_key text,item_name text,item_type text,item_rarity text,price_gp numeric,merchant_tags text[],payload jsonb);

UPDATE public.items_catalog target
SET item_name=seed.item_name,item_type=seed.item_type,item_rarity=seed.item_rarity,
    price_gp=seed.price_gp,merchant_tags=seed.merchant_tags,payload=seed.payload
FROM _alchemy_v9_catalog_seed seed
WHERE target.item_key=seed.item_key;

INSERT INTO public.items_catalog (item_key,item_name,item_type,item_rarity,price_gp,merchant_tags,payload)
SELECT seed.item_key,seed.item_name,seed.item_type,seed.item_rarity,seed.price_gp,seed.merchant_tags,seed.payload
FROM _alchemy_v9_catalog_seed seed
WHERE NOT EXISTS (SELECT 1 FROM public.items_catalog target WHERE target.item_key=seed.item_key);
COMMIT;
